import type GeoJSON from 'geojson';

import { _getCanvasColor as getCanvasColor } from '@dynatrace/strato-components/charts';
import { _accessValue as accessValue } from '@dynatrace/strato-components/core';

import { calculateHoveredColor } from '../../../utils/calculate-hovered-color.js';
import { defineColor } from '../../../utils/define-color.js';

export const parseRegionDataToGeoJSON = <T extends Record<string, unknown>>(
  mapSource: GeoJSON.FeatureCollection,
  data: T[],
  regionAccessor: string | ((i: T) => string),
  color: string | ((i: T) => string),
): GeoJSON.FeatureCollection => {
  const features = data.reduce((features: GeoJSON.Feature[], item) => {
    let id: string | undefined = '';

    if (typeof regionAccessor === 'function') {
      id = regionAccessor(item);
    } else {
      id = accessValue<string>(item, regionAccessor);
    }

    const feature = mapSource.features.find((region) => region.id === id);
    if (feature !== undefined) {
      const regionColor = defineColor(color, item);
      const canvasColor = getCanvasColor(regionColor);
      const hoveredColor = calculateHoveredColor(canvasColor);
      const { name, region_type } = feature.properties as {
        name: string;
        region_type: string;
      };
      const feat = {
        ...feature,
        properties: {
          name,
          region_type,
          data: item,
          ...item,
          __color: canvasColor,
          __hoveredColor: hoveredColor,
        },
      };

      features.push(feat);
    }

    return features;
  }, []);

  return {
    type: 'FeatureCollection',
    features,
  };
};
